func TestComponent_MultipleConfigValidations(t *testing.T) {
	tests := []struct {
		name      string
		config    Config
		shouldErr bool
	}{
		{
			name: "valid bm25",
			config: Config{
				Ports: &component.PortConfig{
					Inputs: []component.PortDefinition{
						{Name: "entity_watch", Type: "kv-watch", Subject: "ENTITY_STATES"},
					},
					Outputs: []component.PortDefinition{
						{Name: "embeddings", Type: "kv-write", Subject: "EMBEDDINGS_CACHE"},
					},
				},
				EmbedderType: "bm25",
			},
			shouldErr: false,
		},
		{
			name: "valid http with URL",
			config: Config{
				Ports: &component.PortConfig{
					Inputs: []component.PortDefinition{
						{Name: "entity_watch", Type: "kv-watch", Subject: "ENTITY_STATES"},
					},
					Outputs: []component.PortDefinition{
						{Name: "embeddings", Type: "kv-write", Subject: "EMBEDDINGS_CACHE"},
					},
				},
				EmbedderType: "http",
				EmbedderURL:  "http://localhost:8080",
			},
			shouldErr: false,
		},
		{
			name: "invalid - http without URL",
			config: Config{
				Ports: &component.PortConfig{
					Inputs: []component.PortDefinition{
						{Name: "entity_watch", Type: "kv-watch", Subject: "ENTITY_STATES"},
					},
					Outputs: []component.PortDefinition{
						{Name: "embeddings", Type: "kv-write", Subject: "EMBEDDINGS_CACHE"},
					},
				},
				EmbedderType: "http",
			},
			shouldErr: true,
		},
		{
			name: "invalid - unknown embedder type",
			config: Config{
				Ports: &component.PortConfig{
					Inputs: []component.PortDefinition{
						{Name: "entity_watch", Type: "kv-watch", Subject: "ENTITY_STATES"},
					},
					Outputs: []component.PortDefinition{
						{Name: "embeddings", Type: "kv-write", Subject: "EMBEDDINGS_CACHE"},
					},
				},
				EmbedderType: "unknown",
			},
			shouldErr: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := tt.config.Validate()
			if tt.shouldErr {
				assert.Error(t, err)
			} else {
				assert.NoError(t, err)
			}
		})
	}
}

